class Solution {
public:
    vector<vector<int>> combine(int n, int k) {
        vector<vector<int>> res;
        vector<int> path;
        backtrack(1, n, k, path, res);
        return res;
    }

    void backtrack(int start, int end, int k, vector<int>& path, vector<vector<int>>& res) {
        if (path.size() == k) {
            res.push_back(path);
            return;
        }
        for (int i = start; i <= end; i++) {
            path.push_back(i);
            backtrack(i + 1, end, k, path, res);
            path.pop_back();
        }
    }
};
```

